import '../lib/model.dart';
import '../lib/outbox.dart';
import '../lib/replica.dart';

void check(bool condition, String message) {
  if (!condition) throw StateError(message);
}

void main() {
  final queue = Outbox();
  queue.enqueue(Mutation(
    id: 'unsent-ack',
    key: 'note',
    value: 'keep me',
    basedOnRevision: 6,
  ));
  check(queue.openSession(101).length == 1, 'initial delivery is available');
  final afterReconnect = queue.openSession(102);
  check(
    afterReconnect.map((item) => item.id).toList().join(',') == 'unsent-ack',
    'unacknowledged work must be offered to the replacement session',
  );

  final replica = Replica(
    revision: 6,
    values: {'note': 'server copy', 'presence': 'old'},
  );
  replica.edit('local-note', 'note', 'offline copy');
  replica.receiveSnapshot(Snapshot(9, {
    'note': 'remote copy',
    'presence': 'new',
  }));
  check(
    replica.visible['note'] == 'offline copy',
    'a reconnect snapshot must not hide pending local intent',
  );
  check(replica.visible['presence'] == 'new', 'remote changes still merge in');
  check(
    replica.outbox.pending.single.basedOnRevision == 9,
    'pending intent is rebased to the received revision',
  );
}
